t.script:
// Datos inyectados desde el controller
const PROYECTO_ID =

;
const MIEMBROS =

;
const ETAPAS   =

;
const ESCANERES =

;

// Reglas de visibilidad de columnas por etapa (nombre en minúsculas)
const REGLAS_ETAPA = {
    'limpieza':     { caja: true,  expedientes: true,  folios: true,  escaneos: false, escaner: false, expEditados: false, foliosEditados: false, expIndexados: false, foliosIndexados: false },
    'ordenado':     { caja: true,  expedientes: true,  folios: true,  escaneos: false, escaner: false, expEditados: false, foliosEditados: false, expIndexados: false, foliosIndexados: false },
    'digitalizado': { caja: true,  expedientes: true,  folios: true,  escaneos: true,  escaner: true,  expEditados: false, foliosEditados: false, expIndexados: false, foliosIndexados: false },
    'editado':      { caja: false, expedientes: false, folios: false, escaneos: false, escaner: false, expEditados: true,  foliosEditados: true,  expIndexados: false, foliosIndexados: false },
    'indexado':     { caja: false, expedientes: false, folios: false, escaneos: false, escaner: false, expEditados: false, foliosEditados: false, expIndexados: true,  foliosIndexados: true  },
};
const REGLA_DEFAULT = { caja: true, expedientes: true, folios: true, escaneos: false, escaner: false, expEditados: false, foliosEditados: false, expIndexados: false, foliosIndexados: false };

// Inicializar fecha al día de hoy
document.getElementById('campo-fecha').valueAsDate = new Date();

// ── Construir opciones de select ──
function opcionesSelect(lista) {
    return lista.map(function(i) {
        return `
${i.name}
`;
    }).join('');
}

// ── Crear una nueva fila ──
let contadorFila = 0;
function crearFila() {
    contadorFila++;
    const id = `fila-${contadorFila}`;
    const tr = document.createElement('tr');
    tr.id = id;
    tr.innerHTML = `


        — Seleccionar —
        ${opcionesSelect(MIEMBROS)}




        — Seleccionar —
        ${ETAPAS.map(function(e) {
            return `
        ${e.name}
        `;
        }).join('')}















    ${opcionesSelect(ESCANERES)}





















`;

    // Escuchar cambio de etapa para actualizar visibilidad de columnas
    tr.querySelector('.sel-etapa').addEventListener('change', function() {
        actualizarColumnasFila(tr, this);
    });

    // Eliminar fila
    tr.querySelector('.btn-eliminar-fila').addEventListener('click', function() {
        tr.remove();
    });

    // Aplicar reglas por defecto (ocultar todo excepto básicos)
    actualizarColumnasFila(tr, tr.querySelector('.sel-etapa'));

    return tr;
}

// ── Actualizar visibilidad de celdas según etapa ──
function actualizarColumnasFila(tr, selectEtapa) {
    const option = selectEtapa.selectedOptions[0];
    const nombre = (option ? option.dataset.nombre || '' : '').toLowerCase();
    const regla = REGLAS_ETAPA[nombre] || REGLA_DEFAULT;

    const mapa = {
        'col-caja':              regla.caja,
        'col-expedientes':       regla.expedientes,
        'col-folios':            regla.folios,
        'col-escaneos':          regla.escaneos,
        'col-escaner':           regla.escaner,
        'col-exp-editados':      regla.expEditados,
        'col-folios-editados':   regla.foliosEditados,
        'col-exp-indexados':     regla.expIndexados,
        'col-folios-indexados':  regla.foliosIndexados,
    };

    for (const [cls, visible] of Object.entries(mapa)) {
        const td = tr.querySelector(`.${cls}`);
        if (td) {
            const inp = td.querySelector('input, select');
            if (inp) {
                inp.disabled = !visible;
                inp.style.visibility = visible ? 'visible' : 'hidden';
                // Resetear valor si se deshabilita
                if (!visible) {
                    if (inp.type === 'number') inp.value = 0;
                    else if (inp.tagName === 'SELECT') Array.from(inp.options).forEach(function(o) { o.selected = false; });
                    else inp.value = '';
                }
            }
        }
    }
}

// ── Agregar primera fila automáticamente ──
document.getElementById('tbody-registros').appendChild(crearFila());

// ── Botón agregar fila ──
document.getElementById('btn-agregar-fila').addEventListener('click', function() {
    document.getElementById('tbody-registros').appendChild(crearFila());
});

// ── Guardar registros ──
document.getElementById('btn-guardar').addEventListener('click', async function() {
    const fecha = document.getElementById('campo-fecha').value;
    if (!fecha) {
        mostrarAlerta('warning', 'Por favor selecciona la fecha de la jornada.');
        return;
    }

    const filas = Array.from(document.querySelectorAll('#tbody-registros tr'));
    if (filas.length === 0) {
        mostrarAlerta('warning', 'Agrega al menos una fila antes de guardar.');
        return;
    }

    const payload = [];
    for (const tr of filas) {
        const miembroId = parseInt(tr.querySelector('.sel-miembro').value);
        const etapaId   = parseInt(tr.querySelector('.sel-etapa').value);
        if (!miembroId || !etapaId) {
            mostrarAlerta('warning', 'Por favor, selecciona un Integrante y una Etapa en todas las filas agregadas.');
            return;
        }

        const escaner = Array.from(tr.querySelector('.sel-escaner').selectedOptions)
                             .map(function(o) { return parseInt(o.value); });

        payload.push({
            miembro_id:          miembroId,
            etapa_id:            etapaId,
            referencia_cajas:    tr.querySelector('.inp-caja').value || null,
            no_expedientes:      parseInt(tr.querySelector('.inp-expedientes').value) || 0,
            total_folios:        parseInt(tr.querySelector('.inp-folios').value) || 0,
            total_escaneos:      parseInt(tr.querySelector('.inp-escaneos').value) || 0,
            tipo_escaner_ids:    escaner,
            expedientes_editados:  parseInt(tr.querySelector('.inp-exp-editados').value) || 0,
            folios_editados:       parseInt(tr.querySelector('.inp-folios-editados').value) || 0,
            expedientes_indexados: parseInt(tr.querySelector('.inp-exp-indexados').value) || 0,
            folios_indexados:      parseInt(tr.querySelector('.inp-folios-indexados').value) || 0,
            observacion:           tr.querySelector('.inp-observacion').value || null,
        });
    }

    const btn = document.getElementById('btn-guardar');
    btn.disabled = true;
    btn.innerHTML = `

Guardando...`;

    try {
        // CSRF token de la cookie de Odoo
        const csrf = getCookie('csrf_token') || '';

        const resp = await fetch(
            `/digitalizacion/api/v1/proyectos/${PROYECTO_ID}/registros`,
            {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRFToken': csrf,
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: { fecha: fecha, filas: payload },
                }),
            }
        );

        const data = await resp.json();

        if (data.result) {
            if (data.result.success) {
                mostrarAlerta('success', `✓ ${payload.length} registro(s) guardado(s) correctamente.`);
                // Limpiar tabla
                document.getElementById('tbody-registros').innerHTML = '';
                document.getElementById('tbody-registros').appendChild(crearFila());
            } else {
                let msg = 'Error desconocido al guardar.';
                if (data.result.error) {
                    if (data.result.error.message) {
                        msg = data.result.error.message;
                    }
                }
                mostrarAlerta('danger', msg);
            }
        } else if (data.error) {
            if (data.error.message) {
                mostrarAlerta('danger', data.error.message);
            } else {
                mostrarAlerta('danger', 'Error desconocido al guardar.');
            }
        } else {
            mostrarAlerta('danger', 'Error desconocido al guardar.');
        }
    } catch(err) {
        mostrarAlerta('danger', 'Error de conexión. Verifica tu acceso a internet.');
        console.error(err);
    } finally {
        btn.disabled = false;
        btn.innerHTML = `

Guardar registros`;
    }
});

// ── Helpers ──
function mostrarAlerta(tipo, mensaje) {
    const el = document.getElementById('alerta-resultado');
    el.className = `alert alert-${tipo} alert-dismissible`;
    el.innerHTML = `${mensaje}

`;
    el.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function getCookie(name) {
    const match = document.cookie.match(new RegExp('(^| )' + name + '=([^;]+)'));
    return match ? decodeURIComponent(match[2]) : null;
}
